    const n = s.length;
    let maxLen = 0;

    // Helper function to find the maximum balanced subarray length in a given string
    const maxBalancedSubarray = (str) => {
        const len = str.length;
        let currentMax = 0;

        // Use prefix sums/balance array approach
        // balance[i] = count('1') - count('0') in str[0...i-1]
        const balance = new Array(len + 1).fill(0);
        for (let i = 0; i < len; i++) {
            balance[i + 1] = balance[i] + (str[i] === '1' ? 1 : -1);
        }

        // A subarray str[i...j-1] is balanced if balance[j] - balance[i] == 0, i.e., balance[j] == balance[i]
        const firstOccurrence = new Map();
        firstOccurrence.set(0, -1); // Balance 0 occurs before index 0 (i.e., at index -1)

        for (let j = 1; j <= len; j++) {
            const currentBalance = balance[j];
            if (firstOccurrence.has(currentBalance)) {
                const i = firstOccurrence.get(currentBalance);
                // Length of subarray str[i+1...j] is j - (i + 1) + 1 = j - i
                currentMax = Math.max(currentMax, j - 1 - i);
            } else {
                firstOccurrence.set(currentBalance, j - 1);
            }
        }
        return currentMax;
    };

    // 1. Case: No swap (or swap two identical characters, which results in the original string)
    maxLen = Math.max(maxLen, maxBalancedSubarray(s));

    // 2. Case: One swap
    // Iterate over all possible pairs (i, j) such that i < j
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            // Only perform a swap if the characters are different
            if (s[i] !== s[j]) {
                const sArr = s.split('');
                // Perform the swap
                [sArr[i], sArr[j]] = [sArr[j], sArr[i]];
                const sSwapped = sArr.join('');

                // Calculate max balanced subarray length for the swapped string
                const currentMax = maxBalancedSubarray(sSwapped);
                maxLen = Math.max(maxLen, currentMax);
            }
        }
    }

    return maxLen;
}

